#include <bits/stdc++.h>
using namespace std;

int main() {
    double x;
    cin >> x;

    if (x <= 2000.0) {
        cout << "Isento" << endl;
        return 0;
    }

    double tax = 0.0;
    // 区间 (2000, 3000] 按 8%
    if (x > 3000.0) tax += 1000.0 * 0.08;
    else tax += (x - 2000.0) * 0.08;

    // 区间 (3000, 4500] 按 18%
    if (x > 4500.0) tax += 1500.0 * 0.18;
    else if (x > 3000.0) tax += (x - 3000.0) * 0.18;

    // 区间 (4500, +∞) 按 28%
    if (x > 4500.0) tax += (x - 4500.0) * 0.28;

    cout << fixed << setprecision(2) << "R$ " << tax << endl;
    return 0;
}
